// ---------------------------------------------------------------------------
// Auto-curated top stories — generated by the editorial pipeline, stored in
// Supabase, and served to the homepage. Falls back to the hand-curated issue
// in lib/issues.ts when nothing has been generated yet.
// ---------------------------------------------------------------------------

import { supabase } from "@/lib/supabase";

export type AutoStory = {
  headline: string;
  url: string;
  source: string;
  category: string;
  oneliner: string; // one-sentence analyst-style take
  image: string | null;
  rank?: number;    // 1-15 from Claude; used for rolling article pool
};

export type AutoPodcast = {
  show: string;        // "The Circuit" | "Chip Stock Investor" | "Invest Like the Best"
  title: string;       // episode title (exact from RSS)
  url: string;         // episode link
  image: string | null; // show artwork or episode image from RSS
  oneliner: string;    // why semiconductor investors should listen to this specific episode
};

export type HomepageContent = {
  topStories: AutoStory[];
  podcasts: AutoPodcast[];  // one pick per show, most relevant to semi investors
  issueTitle: string; // e.g. "Week of May 26, 2026"
  generatedAt: string; // ISO timestamp
};

const TABLE = "homepage_content";
const KEY = "top_stories";

// The pipeline can emit the same article twice (e.g. picked under two
// categories). The homepage keys stories by URL, so drop repeats here.
function dedupeByUrl<T extends { url: string }>(items: T[]): T[] {
  const seen = new Set<string>();
  return items.filter((item) => !seen.has(item.url) && seen.add(item.url));
}

export async function getHomepageContent(): Promise<HomepageContent | null> {
  try {
    const { data, error } = await supabase
      .from(TABLE)
      .select("data, generated_at")
      .eq("key", KEY)
      .single();
    if (error || !data) return null;
    const content = data.data as HomepageContent;
    return {
      ...content,
      topStories: dedupeByUrl(content.topStories ?? []),
      podcasts: dedupeByUrl(content.podcasts ?? []),
    };
  } catch {
    return null;
  }
}

// ---------------------------------------------------------------------------
// Rolling article pool — homepage_articles table
// ---------------------------------------------------------------------------

const ARTICLES_TABLE = "homepage_articles";

function rowToStory(row: Record<string, unknown>): AutoStory {
  return {
    headline: row.headline as string,
    url: row.url as string,
    source: row.source as string,
    category: row.category as string,
    oneliner: row.oneliner as string,
    image: (row.image as string | null) ?? null,
    rank: row.rank as number,
  };
}

/** Read the current article pool and split into top stories + list. */
export async function getHomepageArticles(): Promise<{
  topStories: AutoStory[];
  listStories: AutoStory[];
}> {
  try {
    const { data, error } = await supabase
      .from(ARTICLES_TABLE)
      .select("*")
      .order("rank", { ascending: true });

    if (error || !data || data.length === 0) return { topStories: [], listStories: [] };

    const now = Date.now();
    const DAY_MS = 24 * 60 * 60 * 1000;

    // All articles live for 3 days regardless of rank —
    // so at any time the pool has today's + yesterday's + day-before-yesterday's.
    const alive = data.filter((r) => {
      const age = now - new Date(r.first_seen_at as string).getTime();
      return age < 3 * DAY_MS;
    });

    // Bucket articles by age tier (no pre-cap — we enforce it globally below)
    const today    = alive.filter((r) => now - new Date(r.first_seen_at as string).getTime() < DAY_MS);
    const yesterday = alive.filter((r) => {
      const age = now - new Date(r.first_seen_at as string).getTime();
      return age >= DAY_MS && age < 2 * DAY_MS;
    });
    const dayBefore = alive.filter((r) => {
      const age = now - new Date(r.first_seen_at as string).getTime();
      return age >= 2 * DAY_MS && age < 3 * DAY_MS;
    });

    // Top Stories: best 4 from today (rank asc = most important first)
    const topStories = today.slice(0, 4).map(rowToStory);
    const topUrls = new Set(topStories.map((s) => s.url));

    // List: fill to guarantee minimums — 8 today, 4 yesterday, 4 day-before
    const todayRemainder = today.filter((r) => !topUrls.has(r.url as string));
    const todayList    = todayRemainder.slice(0, Math.max(8 - topStories.length, 4));
    const usedUrls     = new Set([...topUrls, ...todayList.map((r) => r.url as string)]);
    const yesterdayList = yesterday.filter((r) => !usedUrls.has(r.url as string)).slice(0, 4);
    yesterdayList.forEach((r) => usedUrls.add(r.url as string));
    const dayBeforeList = dayBefore.filter((r) => !usedUrls.has(r.url as string)).slice(0, 4);

    // Combine then enforce hard source cap of 2 across the ENTIRE page output
    const allCandidates = [
      ...topStories,
      ...[...todayList, ...yesterdayList, ...dayBeforeList].map(rowToStory),
    ];
    const finalCounts = new Map<string, number>();
    const cappedTop: AutoStory[] = [];
    const cappedList: AutoStory[] = [];
    const topUrlSet = new Set(topStories.map((s) => s.url));

    for (const story of allCandidates) {
      const src = story.source.toLowerCase().trim().replace(/\s+/g, " ");
      const isDigitimes = src === "digitimes";
      const cap = isDigitimes ? 1 : 2;
      const count = finalCounts.get(src) ?? 0;
      if (count >= cap) continue;
      // Digitimes can never be a top story
      if (isDigitimes && topUrlSet.has(story.url)) continue;
      finalCounts.set(src, count + 1);
      if (topUrlSet.has(story.url) && cappedTop.length < 4) {
        cappedTop.push(story);
      } else {
        cappedList.push(story);
      }
    }

    return { topStories: cappedTop, listStories: cappedList };
  } catch {
    return { topStories: [], listStories: [] };
  }
}

/** Upsert today's ranked picks and expire stale articles. */
export async function saveAndExpireArticles(
  stories: AutoStory[],
): Promise<{ ok: boolean; error?: string }> {
  try {
    const now = new Date().toISOString();
    const urls = stories.map((s) => s.url);

    // Fetch existing rows to preserve first_seen_at + original_rank on update
    const { data: existing } = await supabase
      .from(ARTICLES_TABLE)
      .select("url, first_seen_at, original_rank")
      .in("url", urls);

    const existingMap = new Map(
      (existing ?? []).map((r) => [r.url as string, r]),
    );

    const rows = stories.map((s) => {
      const ex = existingMap.get(s.url);
      return {
        url: s.url,
        headline: s.headline,
        source: s.source,
        category: s.category,
        oneliner: s.oneliner,
        image: s.image ?? null,
        rank: s.rank ?? 99,
        original_rank: ex ? (ex.original_rank as number) : (s.rank ?? 99),
        first_seen_at: ex ? (ex.first_seen_at as string) : now,
        last_seen_at: now,
      };
    });

    const { error: upsertError } = await supabase
      .from(ARTICLES_TABLE)
      .upsert(rows, { onConflict: "url" });

    if (upsertError) return { ok: false, error: upsertError.message };

    // Expire articles older than 3 days — all tiers same shelf life.
    // Articles re-picked in this run are never expired (kept their first_seen).
    const keep = new Set(urls);
    const DAY = 24 * 60 * 60 * 1000;
    const nowMs = Date.now();

    const { data: allRows } = await supabase
      .from(ARTICLES_TABLE)
      .select("url, original_rank, first_seen_at");

    const expiredUrls = (allRows ?? [])
      .filter((r) => {
        if (keep.has(r.url as string)) return false;
        const age = nowMs - new Date(r.first_seen_at as string).getTime();
        return age >= 3 * DAY;
      })
      .map((r) => r.url as string);

    if (expiredUrls.length > 0) {
      // Delete in chunks to keep the URL list well within request limits.
      for (let i = 0; i < expiredUrls.length; i += 50) {
        await supabase
          .from(ARTICLES_TABLE)
          .delete()
          .in("url", expiredUrls.slice(i, i + 50));
      }
    }

    return { ok: true };
  } catch (e) {
    return { ok: false, error: String(e) };
  }
}

// ---------------------------------------------------------------------------
// Full RSS article archive — all fetched items, not just the top 15.
// Powers the chatbot's current-events knowledge base.
// ---------------------------------------------------------------------------

const RSS_TABLE = "rss_articles";

export type RssArchiveItem = {
  url: string;
  title: string;
  description: string;
  source: string;
  pub_date: string | null;
};

/** Save all RSS items fetched during a cron run. Upserts on URL, expires >21-day-old rows. */
export async function saveRssArticles(
  items: { title: string; description: string; link: string; source: string; pubDate: string }[],
): Promise<void> {
  if (!items.length) return;
  const now = new Date().toISOString();
  const rows = items.map((item) => ({
    url: item.link,
    title: item.title.slice(0, 500),
    description: item.description.slice(0, 800),
    source: item.source,
    pub_date: item.pubDate ? new Date(item.pubDate).toISOString() : null,
    fetched_at: now,
  })).filter((r) => r.url);

  // Upsert in chunks to stay within request limits.
  for (let i = 0; i < rows.length; i += 100) {
    await supabase.from(RSS_TABLE).upsert(rows.slice(i, i + 100), { onConflict: "url" });
  }

  // Expire rows older than 21 days.
  const cutoff = new Date(Date.now() - 21 * 24 * 60 * 60 * 1000).toISOString();
  await supabase.from(RSS_TABLE).delete().lt("pub_date", cutoff);
}

/** Fetch recent RSS articles for chatbot context — most recent first, up to limit. */
export async function getRssArticles(limit = 60): Promise<RssArchiveItem[]> {
  try {
    const { data, error } = await supabase
      .from(RSS_TABLE)
      .select("url, title, description, source, pub_date")
      .order("pub_date", { ascending: false })
      .limit(limit);
    if (error || !data) return [];
    return data as RssArchiveItem[];
  } catch {
    return [];
  }
}

export async function saveHomepageContent(
  content: HomepageContent,
): Promise<{ ok: boolean; error?: string }> {
  try {
    const { error } = await supabase.from(TABLE).upsert(
      { key: KEY, data: content, generated_at: content.generatedAt },
      { onConflict: "key" },
    );
    return { ok: !error, error: error?.message };
  } catch (e) {
    return { ok: false, error: String(e) };
  }
}
